% Temporary file to do testing on old data %[output:90093e61] %[output:3ff9fad8] %[output:08ef0342]


i=4;
j=1;
num_points = 400;


channel = 108; %[control:editfield:4c3c]{"position":[11,14]}
numSubC = 30; %[control:editfield:6aa2]{"position":[11,13]}

% Obtain signal settings
[centerFrequency,bandwidth] = channelFrequency(channel);
lambda = physconst('LightSpeed')/centerFrequency;


nbeta =          720; % azimuth resolution %[control:editfield:1f35]{"position":[18,21]}
ngamma =         90; % elevation resolution %[control:editfield:8910]{"position":[18,20]}
beta_min = -180; % minimum azimuth %[control:slider:58b8]{"position":[12,16]}
beta_max = 0; % maximum azimuth %[control:slider:1144]{"position":[12,13]}
gamma_min = 90; % minimum elevation %[control:slider:69e3]{"position":[13,15]}
gamma_max = 180; % maximum elevation %[control:slider:29cc]{"position":[13,16]}
betaList = linspace(deg2rad(beta_min), deg2rad(beta_max), nbeta).';
gammaList = linspace(deg2rad(gamma_min), deg2rad(gamma_max), ngamma);

movingWindow = 1*num_points; %rendezvous
       
% Preprocessed timetable with all data for Bartlett estimation
ppData = preProcessBartlett(R(i).csiT, R(j).csiT, R(i).odomT, ...
    R(i).MAC, R(j).MAC, movingWindow, numSubC);
pause(0.1)

% Check if data is retrieved
if isempty(ppData)
    error("Missing preprocessing data, skipping i=%o, j=%i",i,j)
end

% Compute the AOA profile using Bartlett
[AOA_profile, AOA_angle] = bartlett_AOA_estimator(ppData.CSI, ppData.yawList, ppData.pitchList, ...
ppData.rhoList, lambda, betaList, gammaList, false);
pause(0.1)


% 6 extractor functions for the different use of pose or odom
fPoseStart = @(x) x.poseT{1,  ["pos_x","pos_y","pos_z"]};
fPoseEnd   = @(x) x.poseT{end, ["pos_x","pos_y","pos_z"]};
fPoseMean  = @(x) mean(x.poseT{:,  ["pos_x","pos_y","pos_z"]});
fOdomStart = @(x) x.odomT{1,  ["pos_x","pos_y","pos_z"]};
fOdomEnd   = @(x) x.odomT{end, ["pos_x","pos_y","pos_z"]};
fOdomMean = @(x) mean(x.odomT{:, ["pos_x","pos_y","pos_z"]});
% Wrapper function to get desired position
fPos = @(R, f) reshape(cell2mat(arrayfun(f, R, 'UniformOutput', false)), 3, numel(R) )';
% Wrapper function to add spawnpos
fPosAddSpawn = @(R, f, spawnPos, addStartPos2Odom) fPos(R,f) + (spawnPos(:,1:3) * addStartPos2Odom);

% Select which position to use for validation metrics.
bearingPos = fPos(R,fPoseMean);

 % Calculate true AoA
rPos = bearingPos(i,:);
tPos = bearingPos(j,:);
[true_azimuth_ji, true_elevation_ji] = calculate_bearing(rPos, tPos);

plotVisible=true;

figsAoA{i,j} = makePlotAoA(AOA_profile, betaList,gammaList, plotVisible, true_azimuth_ji, true_elevation_ji); %[output:6c816aeb] %[output:29914b18] %[output:6b1dac6f] %[output:3413b2ad]

